\paragraph{Vision--Language--Action (VLA) Models.}
% VLA models aim to equip embodied agents with a unified interface for perception, reasoning, and control in the physical world.
% Formally, a VLA policy $\pi_\theta$ is defined as an autoregressive conditional distribution that maps a sequence of past observations $o_{1:t}$, action history $a_{1:t-1}$, and a natural language goal $g$ to the next action $a_t$.
% Given an initial context $c=(o_1, g)$, the policy induces a rollout distribution:
% % \begin{equation}
% % \pi_{\theta}(a_{1:T} \mid o_{1:T}, g)
% % =
% % \prod_{t=1}^{T}
% % \pi_{\theta}(a_t \mid o_{1:t}, a_{1:t-1}, g).
% % \end{equation}
% $\pi_{\theta}(a_{1:T} \mid o_{1:T}, g)
% =
% \prod_{t=1}^{T}
% \pi_{\theta}(a_t \mid o_{1:t}, a_{1:t-1}, g)$.
% The learning objective is to optimize $\pi_\theta$ to maximize the expected task return under this rollout distribution.
% % Most existing VLA systems acquire generalizable visuomotor capabilities through large-scale imitation learning, followed by supervised fine-tuning (SFT) for task specialization.
We consider language-conditioned robotic manipulation, where at each timestep the model receives a visual observation $o_t \in \mathcal{O}$, a language instruction $g \in \mathcal{G}$, and optionally proprioceptive state $p_t \in \mathcal{P}$, and outputs an action $a_t \in \mathcal{A}$. Given an expert dataset $\mathcal{D}_{\text{expert}} = \{(g, \tau)\}$, where $\tau = \{(o_1, p_1, a_1), \dots, (o_T, p_T, a_T)\}$, a VLA model $\pi_\theta$ is modeled as a conditional distribution over actions, i.e., $\pi_\theta(a_{1:T} \mid o_{1:T}, p_{1:T}, g) = \prod_{t=1}^{T} \pi_\theta(a_t \mid o_{1:t}, p_{1:t}, a_{1:t-1}, g)$. In practice, the VLA model predicts short action sequences conditioned on the current context, $\pi_\theta(a_{t:t+H} \mid o_t, p_t, g)$, and is trained via maximum likelihood on $\mathcal{D}_{\text{expert}}$.

\paragraph{Model Predictive Control (MPC).}
MPC~\citep{garcia1989model} is a general paradigm for model-based decision making, where actions are selected by optimizing predicted future trajectories over a finite horizon.
At each decision step $t$, MPC solves:
% \begin{equation}
% a_{t:t+H}^\star
% =
% \arg\max_{a_{t:t+H}}
% \mathbb{E}
% \left[
% \sum_{i=0}^{H}
% \gamma^{i}
% R(s_{t+i}, a_{t+i})
% \right],
% \end{equation}
\(
\textstyle
a_{t:t+H}^\star
=
\arg\max_{a_{t:t+H}}
\mathbb{E}
\left[
\sum_{i=0}^{H}
\gamma^{i}
R(s_{t+i}, a_{t+i})
\right]
\),
where $\gamma \in (0,1)$ is a discount factor and $R(\cdot)$ denotes the reward function.
Candidate trajectories are evaluated by rolling out a learned world model.
By explicitly reasoning over future trajectories, MPC achieves improved robustness and sample efficiency compared to purely reactive, model-free policies.

\paragraph{Language-Conditioned Video Generation Module.}
The video generation module predicts future visual trajectories conditioned on both past observations and task-level language instructions.
Given an instruction $g$, a frozen T5-XXL encoder~\citep{raffel2020exploring} produces a sequence of language embeddings
$\mathcal{T}(g) \in \mathbb{R}^{L_g \times d_t}$,
which are injected into a Diffusion Transformer (DiT)~\citep{peebles2023scalable} backbone via cross-attention.
Let $i \in \{h,l,r\}$ index camera views (e.g., head, left, right).
We denote by $\textstyle v_0^{(i)}$ the encoded initial observation, $\textstyle v_{\hat{t}}^{(i)}$ a sparse visual memory at time $\textstyle \hat{t}$, and $\textstyle z^{(i)} \sim \mathcal{N}(0,I)$ a view-specific latent noise variable.
The video generation module $\mathcal{W}$ predicts the next visual segment as
% \begin{equation}
% \hat{x}_{t:t+N}
% =
% \mathcal{W}\!\left(
% \{v_0^{(i)}, v_{\hat{t}}^{(i)}, z^{(i)}\}_{i},
% \mathcal{T}(g)
% \right).
% \end{equation}
$\textstyle \hat{x}_{t:t+N} = \mathcal{W}\!\big(\{v_0^{(i)}, v_{\hat{t}}^{(i)}, z^{(i)}\}_{i}, \mathcal{T}(g)\big)$.
By jointly conditioning on multi-view visual history, stochastic latent variables, and language semantics, $\mathcal{W}$ captures both task intent and spatiotemporal dynamics.
Video generation proceeds autoregressively, yielding a temporally coherent visual rollout that represents the policy’s future execution.
Here, with a slight abuse of notation, we use $\mathcal{W}$
to denote the visual rollout component of the latent trajectory generator
$\mathcal{W}_\theta$ introduced in Section~\ref{sec:theory},
which produces the visual subspace of a full state--action trajectory.
\paragraph{Trajectory Value and Action Decoding Modules.}
Both the trajectory value and action decoding modules adopt a DiT-based autoregressive architecture operating on latent trajectory representations.
Visual features are first transformed into temporally structured tokens, which are then evaluated and decoded into actions.
At DiT block $i$, video tokens are processed as
% \begin{equation}
% \mathbf{x}_i
% =
% \mathcal{B}_i^{\mathrm{vid}}
% \left(
% \mathbf{x}_{\mathrm{in}}, \mathcal{T}(g)
% \right),
% \end{equation}
$\mathbf{x}_i = \mathcal{B}_i^{\mathrm{vid}}\left(\mathbf{x}_{\mathrm{in}}, \mathcal{T}(g)\right)$,
where $\mathcal{B}_i^{\mathrm{vid}}$ denotes the $i^{th}$ visual transformer block.
The trajectory value module initializes a latent value token
$\mathbf{z}_{\mathrm{val}} \sim \mathcal{N}(0,I)$
and refines it through cross-attention with video features:
% \begin{equation}
% \mathbf{u}_i
% =
% \mathcal{B}_i^{\mathrm{val}}
% \left(
% \mathbf{z}_{\mathrm{val}},
% \operatorname{CrossAttn}(\mathbf{z}_{\mathrm{val}}, \mathbf{x}_i)
% \right),
% \end{equation}
$\mathbf{u}_i = \mathcal{B}_i^{\mathrm{val}}\big(\mathbf{z}_{\mathrm{val}}, \operatorname{CrossAttn}(\mathbf{z}_{\mathrm{val}}, \mathbf{x}_i)\big)$,
where $\mathbf{u}_i$ represents the latent trajectory value embedding.
The action decoder initializes latent action tokens $\mathbf{z}_{\mathrm{act}}$ and sequentially integrates video and value feature:
% {\footnotesize
% \begin{subequations}
% \begin{align}
% \mathbf{z}_{\mathrm{act}}^{(i)}
% &=
% \mathcal{B}_i^{\mathrm{act}}
% \left(
% \mathbf{z}_{\mathrm{act}}^{(i-1)},
% \operatorname{CrossAttn}(\mathbf{z}_{\mathrm{act}}^{(i-1)}, \mathbf{x}_i)
% \right), \\
% \mathbf{a}_i
% &=
% \mathcal{B}_i^{\mathrm{act}}
% \left(
% \mathbf{z}_{\mathrm{act}}^{(i)},
% \operatorname{CrossAttn}(\mathbf{z}_{\mathrm{act}}^{(i)}, \mathbf{u}_i)
% \right).
% \end{align}
% \label{eq:action}
% \end{subequations}
% }
{
% \footnotesize
\begin{equation}
\begin{aligned}
\mathbf{z}_{\mathrm{act}}^{(i)}
&=
\mathcal{B}_i^{\mathrm{act}}\!\left(
\mathbf{z}_{\mathrm{act}}^{(i-1)},
\operatorname{CrossAttn}(\mathbf{z}_{\mathrm{act}}^{(i-1)}, \mathbf{x}_i)
\right), \text{and } 
\mathbf{a}_i
=
\mathcal{B}_i^{\mathrm{act}}\!\left(
\mathbf{z}_{\mathrm{act}}^{(i)},
\operatorname{CrossAttn}(\mathbf{z}_{\mathrm{act}}^{(i)}, \mathbf{u}_i)
\right).
\end{aligned}
\label{eq:action}
\end{equation}
}
\paragraph{Training via Flow Matching.}
% We adopt a three-stage training strategy based on flow matching.
% We assume that $x^0, v^0, a^0$ and $x^1, v^1, a^1$ represent samples from the video, trajectory return $\sum_{i=0}^{H} \gamma^i R(s_{t+i}, a_{t+i})$, robot action noise distribution, and target video, trajectory return, and robot action distribution, respectively.
We adopt a three-stage training strategy based on flow matching.
Following standard flow matching formulations,
we assume that $x^0, v^0, a^0$ are samples drawn from the corresponding base noise distributions
for video, trajectory return, and robot actions, respectively,
while $x^1, v^1, a^1$ denote samples from the target data distributions,
including the target video trajectories,
the return
$v^1 = \sum_{i=0}^{H} \gamma^i R(s_{t+i}, a_{t+i})$,
and the target robot action distribution.
Here we use a rule-based dense reward function similar to that used in previous work--ReinboT~\citep{zhang2025reinbot} (details in Appendix Sec.~\ref{appendix:Implementation_Details}).
First, the video generation module is trained using a video flow loss:
% \begin{equation}
% \mathcal{L}_{\mathrm{vid}}
% =
% \mathbb{E}
% \left[
% \| v_\theta(t, l, o, x^t) - (x^1 - x^0) \|_2^2
% \right].
% \end{equation}
$\mathcal{L}_{\mathrm{vid}} = \mathbb{E}\!\left[\| v_\theta(t, l, o, x^t) - (x^1 - x^0) \|_2^2 \right]$.
The video model is then frozen, and a trajectory value module is trained to predict cumulative discounted rewards:
% \begin{equation}
% \mathcal{L}_{\mathrm{val}}
% =
% \mathbb{E}
% \left[
% \| v_\theta(t, l, o, z_{\mathrm{vid}}, v^t) - (v^1 - v^0) \|_2^2
% \right].
% \end{equation}
$\mathcal{L}_{\mathrm{val}} = \mathbb{E}\big[\| v_\theta(t, l, o, z_{\mathrm{vid}}, v^t) - (v^1 - v^0) \|_2^2 \big]$.
% where $v^1 = \sum_{i=0}^{H} \gamma^i R(s_{t+i}, a_{t+i})$.
Finally, all modules are jointly trained with an action flow loss:
% \begin{equation}
% \mathcal{L}_{\mathrm{act}}
% =
% \mathbb{E}
% \left[
% \| v_\theta(t, l, o, z_{\mathrm{vid}}, z_{\mathrm{val}}, a^t) - (a^1 - a^0) \|_2^2
% \right].
% \end{equation}
$\mathcal{L}_{\mathrm{act}} = \mathbb{E}\big[\| v_\theta(t, l, o, z_{\mathrm{vid}}, z_{\mathrm{val}}, a^t) - (a^1 - a^0) \|_2^2 \big]$.

