\vspace{-10pt}
\begin{minipage}{0.56\columnwidth}
\begin{algorithm}[H]
\caption{WAV: Latent Trajectory Planning}
\label{alg:latent_mppi}
\begin{algorithmic}[1]
\State Video generator module $\mathcal{W}$, trajectory value module $\mathcal{V}$, initial flow noise distributions $f_{\mathrm{vid}}^{(0)}, f_{\mathrm{val}}^{(0)}$, samples $(M,N)$, elites $(K_1,K_2)$.
\For{iteration $k = 1,\dots,K$}
    \State Sample video latent noise $\mathbf{z}_{\mathrm{vid}}^{(m)} \sim f_{\mathrm{vid}}^{(k-1)}$
    \State Generate video feature $\mathbf{x}^{(m)}$ 
    \For{each video feature $\mathbf{x}^{(m)}$}
        \State Sample value latent noise $\mathbf{z}_{\mathrm{val}}^{(m,n)} \sim f_{\mathrm{val}}^{(k-1)}$
        \State Evaluate values $\mathbf{U}^{(m,n)}$ 
        \State Compute score $\phi^{(m)}$ 
    \EndFor
    \State Update $f_{\mathrm{vid}}^{(k)}$ using top-$K_1$ samples by Eq.~\ref{eq:video_mu_sigma}
    \State Update $f_{\mathrm{val}}^{(k)}$ using top-$K_2$ samples by Eq.~\ref{eq:value_mu_sigma}
\EndFor
\State Sample optimized latent noise $\mathbf{z}_{\mathrm{vid}}^\star, \mathbf{z}_{\mathrm{val}}^\star$
\State Predict action by Eq.~\ref{eq:action}
\end{algorithmic}
\end{algorithm}
